&lt;p&gt;Soit le code suivant. Que va afficher la console après que l'utilisateur a cliqué une fois sur le bouton ?&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;
function Counter() {
  const [count, setCount] = useState(0);

  useEffect(() =&gt; {
    console.log('Effet exécuté');
    return () =&gt; console.log('Nettoyage');
  }, [count]);

  return &lt;button onClick={() =&gt; setCount(c =&gt; c+1)}&gt;{count}&lt;/button&gt;;
}
&lt;/code&gt;&lt;/pre&gt;

&lt;p&gt;Soit le code suivant. Que se passe-t-il quand l'utilisateur clique sur le bouton ?&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;
function Danger() {
  const [count, setCount] = useState(0);

  useEffect(() =&gt; {
    setCount(count + 1);
  });

  return &lt;button onClick={() =&gt; setCount(count + 1)}&gt;{count}&lt;/button&gt;;
}
&lt;/code&gt;&lt;/pre&gt;

&lt;p&gt;Soit le code suivant. Combien de fois 'Effet exécuté' sera affiché au chargement initial ?&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;
useEffect(() =&gt; {
  console.log('Effet exécuté');
}, [props.user.name]);
&lt;/code&gt;&lt;/pre&gt;

&lt;p&gt;Soit le code suivant. Pourquoi utilise-t-on la forme fonctionnelle &lt;code&gt;prev =&gt; prev + 1&lt;/code&gt; dans setCount ?&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;
useEffect(() =&gt; {
  const id = setInterval(() =&gt; {
    setCount(prev =&gt; prev + 1);
  }, 1000);
  return () =&gt; clearInterval(id);
}, []);
&lt;/code&gt;&lt;/pre&gt;
